ci.user_id = #{userId}
AND s.status = 1

    AND EXISTS (
        SELECT 1
        FROM spot_tag_relation str
        INNER JOIN spot_tag st ON str.tag_id = st.id
        WHERE str.spot_id = s.id
          AND st.status = 1
          AND st.tag_code = #{query.tagCode}
    )


    AND c.city_name = #{query.cityName}


    AND ci.checkin_time >= #{checkedInAfter}
